<!doctype html><html><head><meta charset="utf-8"><style>@page{margin:45px 45px 60px}body{font-family:DejaVu Sans,sans-serif;color:#172b4d;font-size:11px}.head{border-bottom:3px solid #175cd3;padding-bottom:14px;margin-bottom:20px}.head h1{margin:0;font-size:24px}.muted{color:#64748b}table{width:100%;border-collapse:collapse;margin:15px 0}th,td{padding:8px;border:1px solid #d7dee8;text-align:left}th{background:#eef5ff}.summary{display:inline-block;margin-right:24px}.footer{position:fixed;bottom:-35px;left:0;right:0;text-align:center;color:#64748b;font-size:9px}.page:after{content:counter(page)}</style></head><body><div class="head"><h1>{{ $branding['platform_name'] ?? $organization->name ?? 'Report Card' }}</h1><div class="muted">Academic progress report · Published state: {{ $reportCard->status->value }}</div></div><h2>{{$reportCard->learner->first_name}} {{$reportCard->learner->last_name}}</h2><p>Learner number: {{$reportCard->learner->learner_number}} · {{$reportCard->period->name}} · {{$reportCard->grade->name}} · {{$reportCard->classGroup->name}} · Version {{$reportCard->version_number}}</p><table><thead><tr><th>Subject</th><th>Valid marked results</th><th>Percentage / status</th><th>Grade</th></tr></thead><tbody>@foreach($reportCard->subjects as $s)<tr><td>{{$s->subject_name_snapshot}} @if($s->subject_code_snapshot)({{$s->subject_code_snapshot}})@endif</td><td>{{$s->marked_assessment_count}}</td><td>{{$s->calculated_percentage === null?str_replace('_',' ',$s->subject_result_status->value):$s->calculated_percentage.'%'}}</td><td>{{$s->grading_band_label}} {{$s->grading_band_symbol}}</td></tr>@endforeach</tbody></table><p><strong>Overall average:</strong> {{$reportCard->overall_average === null?'Not calculated':$reportCard->overall_average.'%'}}</p>@if($reportCard->template->show_attendance)<h3>Attendance summary</h3><p>Based on recorded finalized sessions only: {{$reportCard->attendance_session_count}} sessions · Present {{$reportCard->present_count}} · Absent {